import React from "react";
import "./Gallery.css";

const artworks = [
  {
    id: 1,
    title: "Mona Lisa",
    artist: "Leonardo da Vinci",
    price: "$1,000,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/6/6a/Mona_Lisa.jpg",
  },
  {
    id: 2,
    title: "Grace",
    artist: "Raja Ravi Varma",
    price: "$850,000",
    image: "https://mapacademy.io/wp-content/uploads/2022/04/raja-ravi-varma-maharashtrian-lady-oil-painting-1s.jpg",
  },
  {
    id: 3,
    title: "The Persistence of Memory",
    artist: "Salvador Dalí",
    price: "$620,000",
    image: "https://upload.wikimedia.org/wikipedia/en/d/dd/The_Persistence_of_Memory.jpg",
  },
  {
    id: 4,
    title: "Girl with a Pearl Earring",
    artist: "Johannes Vermeer",
    price: "$740,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/d/d7/Meisje_met_de_parel.jpg",
  },
  {
    id: 5,
    title: "Starry Night",
    artist: "Vincent van Gogh",
    price: "$900,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/e/ea/The_Starry_Night.jpg",
  },
  {
    id: 6,
    title: "Water Lilies",
    artist: "Claude Monet",
    price: "$780,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/0/0a/Claude_Monet_-_Water_Lilies_-_Google_Art_Project.jpg",
  },
  {
    id: 7,
    title: "The Scream",
    artist: "Edvard Munch",
    price: "$950,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/f/f4/The_Scream.jpg",
  },
  {
    id: 8,
    title: "Guernica",
    artist: "Pablo Picasso",
    price: "$1,200,000",
    image: "https://upload.wikimedia.org/wikipedia/en/7/74/PicassoGuernica.jpg",
  },
  {
    id: 9,
    title: "The Kiss",
    artist: "Gustav Klimt",
    price: "$880,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/7/74/Gustav_Klimt_016.jpg",
  },
  {
    id: 10,
    title: "Sunflowers",
    artist: "Vincent van Gogh",
    price: "$830,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/4/4c/Vincent_van_Gogh_-_Sunflowers_-_VGM_F458.jpg",
  },
  {
    id: 11,
    title: "The Two Fridas",
    artist: "Frida Kahlo",
    price: "$720,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/1/1f/Frida_Kahlo_%28self_portrait%29.jpg",
  },
  {
    id: 12,
    title: "Impression, Sunrise",
    artist: "Claude Monet",
    price: "$670,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/5/54/Claude_Monet%2C_Impression%2C_soleil_levant.jpg",
  },
  {
    id: 13,
    title: "The Birth of Venus",
    artist: "Sandro Botticelli",
    price: "$1,100,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/1/1c/Birth_of_Venus_Botticelli.jpg",
  },
  {
    id: 14,
    title: "Shakuntala",
    artist: "Raja Ravi Varma",
    price: "$780,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/3/3b/Shakuntala_by_Raja_Ravi_Varma.jpg",
  },
  {
    id: 15,
    title: "Bharat Mata",
    artist: "Abanindranath Tagore",
    price: "$700,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/9/99/Bharat_Mata.jpg",
  },
  {
    id: 16,
    title: "Mother India",
    artist: "M. F. Husain",
    price: "$880,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/6/6c/MF_Husain_Mother_India.jpg",
  },
  {
    id: 17,
    title: "Village Scene",
    artist: "Jamini Roy",
    price: "$520,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/0/09/Jamini_Roy_-_Village_Scene.jpg",
  },
  {
    id: 18,
    title: "The Swing",
    artist: "Jean-Honoré Fragonard",
    price: "$650,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/2/2b/Fragonard%2C_The_Swing.jpg",
  },
  {
    id: 19,
    title: "American Gothic",
    artist: "Grant Wood",
    price: "$600,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/7/74/Grant_Wood_-_American_Gothic_-_Google_Art_Project.jpg",
  },
  {
    id: 20,
    title: "The Night Watch",
    artist: "Rembrandt",
    price: "$1,050,000",
    image: "https://upload.wikimedia.org/wikipedia/commons/2/2f/The_Nightwatch_by_Rembrandt.jpg",
  },
];

function Gallery() {

  const handleBuy = (title) => {
    alert(`You purchased "${title}"`);
  };

  const handleAddToCart = (title) => {
    alert(`"${title}" added to cart`);
  };

  return (
    <div className="gallery-container">
      <h1 className="gallery-title">Premium Art Collection</h1>

      <div className="gallery-grid">
        {artworks.map((art) => (
          <div key={art.id} className="art-card">
            <img src={art.image} alt={art.title} />
            <h3>{art.title}</h3>
            <p>{art.artist}</p>
            <h4 className="price">{art.price}</h4>

            <button onClick={() => handleAddToCart(art.title)}>
              Add to Cart
            </button>

            <button
              style={{ marginTop: "8px" }}
              onClick={() => handleBuy(art.title)}
            >
              Buy Now
            </button>

          </div>
        ))}
      </div>
    </div>
  );
}

export default Gallery;
